Index: frontend/styles/style.css
===================================================================
--- frontend/styles/style.css	
+++ frontend/styles/style.css	
@@ -0,0 +1,64 @@
+@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@300;400;700&display=swap');
+
+body {
+    font-family: 'Roboto', sans-serif;
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    flex-direction: column;
+    height: 100vh;
+    margin: 0;
+    background: url('../assets/cyberpunk_background.jpg') no-repeat center center fixed;
+    background-size: cover;
+    color: #333;
+}
+
+.container {
+    text-align: center;
+    background: rgba(255, 255, 255, 0.6);
+    padding: 40px;
+    border-radius: 16px;
+    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
+    backdrop-filter: blur(10px);
+    border: 1px solid rgba(255, 255, 255, 0.18);
+    margin-bottom: 20px;
+}
+
+.product-container {
+    text-align: center;
+    background: rgba(255, 255, 255, 0.6);
+    padding: 30px;
+    border-radius: 16px;
+    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.37);
+    backdrop-filter: blur(10px);
+    border: 1px solid rgba(255, 255, 255, 0.18);
+    margin-top: 20px;
+}
+
+h1, h2 {
+    margin-bottom: 10px;
+    font-weight: 700;
+    color: #ffffff;
+}
+
+p {
+    font-weight: 300;
+    color: #eeeeee;
+}
+
+.download-button, .purchase-button {
+    display: inline-block;
+    margin-top: 20px;
+    padding: 12px 30px;
+    font-size: 18px;
+    font-weight: 700;
+    color: #fff;
+    background: linear-gradient(90deg, #667eea, #764ba2);
+    text-decoration: none;
+    border-radius: 8px;
+    transition: background 0.3s ease;
+}
+
+.download-button:hover, .purchase-button:hover {
+    background: linear-gradient(90deg, #764ba2, #667eea);
+}
